"use client"

import { useState, useEffect, useMemo } from "react"
import dynamic from "next/dynamic"
import {
  BarChart,
  Bar,
  Cell,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
  CartesianGrid,
} from "recharts"
import { Info, ChevronLeft, ChevronRight } from "lucide-react"

const Lottie = dynamic(() => import("lottie-react"), { ssr: false })

// ── Types ──────────────────────────────────────────────────────────────────────

type AqiLevel =
  | "very-good"
  | "good"
  | "moderate"
  | "unhealthy"
  | "very-unhealthy"
  | "hazardous"

type TimeRange = "24h" | "30d" | "180d"

type AqiConfig = {
  level: AqiLevel
  label: string
  heroBg: string
  barBg: string
  accent: string
  accentLight: string
}

// ── AQI config ─────────────────────────────────────────────────────────────────

function getAqiConfig(pm25: number): AqiConfig {
  if (pm25 <= 15)
    return { level: "very-good",      label: "Хорошо",                          heroBg: "#d1fae5", barBg: "#059669", accent: "#059669", accentLight: "#d1fae5" }
  if (pm25 <= 35)
    return { level: "good",            label: "Умеренно",                        heroBg: "#ecfccb", barBg: "#65a30d", accent: "#65a30d", accentLight: "#ecfccb" }
  if (pm25 <= 55)
    return { level: "moderate",        label: "Вредно для чувствительных групп", heroBg: "#fef3c7", barBg: "#d97706", accent: "#d97706", accentLight: "#fef3c7" }
  if (pm25 <= 150)
    return { level: "unhealthy",       label: "Вредно",                          heroBg: "#ffedd5", barBg: "#ea580c", accent: "#ea580c", accentLight: "#ffedd5" }
  if (pm25 <= 250)
    return { level: "very-unhealthy",  label: "Очень вредно",                    heroBg: "#f3e8ff", barBg: "#9333ea", accent: "#9333ea", accentLight: "#f3e8ff" }
  return   { level: "hazardous",       label: "Опасно",                          heroBg: "#fee2e2", barBg: "#dc2626", accent: "#dc2626", accentLight: "#fee2e2" }
}

function barColor(pm25: number): string {
  if (pm25 <= 15) return "#22c55e"
  if (pm25 <= 35) return "#a3e635"
  if (pm25 <= 55) return "#f59e0b"
  if (pm25 <= 150) return "#f97316"
  if (pm25 <= 250) return "#a855f7"
  return "#ef4444"
}

